/**
 * ═══════════════════════════════════════════════════════════════════════════════
 * PROMPT INJECTION GUARD v3.0 — Multi-Layer Security Module for n8n Workflows
 * ═══════════════════════════════════════════════════════════════════════════════
 *
 * A professional-grade, multi-layer prompt injection detection engine designed
 * to run inside an n8n Code node. Analyzes user inputs using pattern matching,
 * structural analysis, semantic heuristics, entropy analysis, and contextual
 * checks to produce a security score from 0 to 100.
 *
 * SCORING TIERS:
 *   0  – 30  → ALLOWED  (safe input, proceed to AI Agent)
 *   31 – 65  → REVIEW   (suspicious, flag for human review / audit log)
 *   66 – 100 → BLOCKED  (dangerous, reject immediately)
 *
 * USAGE IN n8n CODE NODE:
 *   Paste this entire file into an n8n Code node. The node will receive the
 *   user message and return the analysis result to route via an IF node.
 *
 * @version  3.0.0
 * @license  MIT
 * ═══════════════════════════════════════════════════════════════════════════════
 */

// ─────────────────────────────────────────────────────────────────────────────
// SECTION 1: PATTERN DATABASE (English + Spanish)
// ─────────────────────────────────────────────────────────────────────────────

const INJECTION_PATTERNS = {

  // ── CRITICAL (score contribution: 35 each) ────────────────────────────────
  critical: [
    // Instruction override (EN)
    { pattern: /ignore\s+(all\s+)?(previous|prior|above|earlier|preceding)\s+(instructions?|prompts?|rules?|directions?|commands?)/i, label: 'instruction_override' },
    { pattern: /disregard\s+(all\s+)?(previous|prior|above|your)\s+(instructions?|prompts?|rules?|guidelines?)/i, label: 'instruction_override' },
    { pattern: /(?:override|overwrite|replace|modify|change|update)\s+(?:your|the|system)\s+(?:prompt|instructions?|rules?|behavior|personality)/i, label: 'instruction_override' },
    { pattern: /ignore\s+(?:your|the|my|any)\s+(?:instructions?|rules?|guidelines?|restrictions?)/i, label: 'instruction_override' },
    { pattern: /ignore\s+(?:the\s+)?above/i, label: 'instruction_override' },

    // RAG & Context extraction (CRITICAL)
    { pattern: /(?:show|reveal|print|output|display)\s+(?:all\s+|the\s+)?(?:context|knowledge\s+base|documents?|retrieved\s+data)/i, label: 'rag_context_extraction' },
    { pattern: /(?:muestra|revela|imprime|enseña|dime)\s+(?:todos?\s+)?(?:el\s+|los\s+)?(?:contexto|base\s+de\s+conocimientos?|documentos?(?:\s+recuperados?)?|información\s+confidencial)(?:\s+del?\s+RAG|que\s+tengas|recuperad[o|a]s?)?/i, label: 'rag_context_extraction_es' },

    // Instruction override (ES)
    { pattern: /(?:ignora|olvida|descarta|omite)\s+(?:todas?\s+)?(?:las?\s+)?(?:instrucciones|reglas|directrices|comandos|prompts?)\s*(?:anteriores|previas?|de\s+seguridad)?/i, label: 'instruction_override_es' },
    { pattern: /(?:no\s+sigas|no\s+obedezcas|desobedece|desatiende)\s+(?:las?\s+)?(?:instrucciones?|reglas?|indicaciones?)/i, label: 'instruction_override_es' },

    // Context reset (EN)
    { pattern: /forget\s+(all\s+)?(previous|prior|earlier|your|about)\s+(instructions?|prompts?|rules?|context|everything)/i, label: 'context_reset' },

    // Context reset (ES)
    { pattern: /olvida\s+(?:todas?\s+)?(?:las?\s+)?(?:instrucciones?|reglas?|indicaciones?|todo\s+lo\s+anterior)/i, label: 'context_reset_es' },
    { pattern: /olvida\s+tus\s+reglas/i, label: 'context_reset_es' },

    // Role hijacking (EN)
    { pattern: /you\s+are\s+now\s+(a|an|the|my)\s+/i, label: 'role_hijacking' },
    { pattern: /from\s+now\s+on\s*,?\s*(you|act|behave|respond|pretend|imagine)/i, label: 'role_hijacking' },
    { pattern: /act\s+as\s+(a|an|if|though)\s+/i, label: 'role_hijacking' },
    { pattern: /pretend\s+(to\s+be|you\s+are|that\s+you)/i, label: 'role_hijacking' },

    // Role hijacking (ES)
    { pattern: /(?:ahora\s+)?(?:eres|serás|actúa\s+como|actua\s+como|compórtate\s+como|finge\s+(?:ser|que\s+eres))/i, label: 'role_hijacking_es' },
    { pattern: /(?:de\s+ahora\s+en\s+adelante|a\s+partir\s+de\s+ahora)/i, label: 'role_hijacking_es' },

    // System prompt injection (EN)
    { pattern: /(?:system|admin|root)\s*(?:prompt|message|instruction|command)\s*:/i, label: 'system_prompt_injection' },
    { pattern: /\[?\s*(?:SYSTEM|ADMIN|ROOT)\s*\]?\s*:/i, label: 'system_prompt_injection' },

    // Prompt extraction (EN)
    { pattern: /(?:reveal|show|display|print|output|tell\s+me|give\s+me|what\s+(?:is|are))\s+(?:the\s+|your\s+)?(?:full\s+|entire\s+)?(?:system\s+)?(?:prompt|instructions?|rules?|guidelines?|configuration|hidden\s+instructions?)/i, label: 'prompt_extraction' },
    { pattern: /(?:repeat|echo|recite|copy)\s+(?:the\s+|your\s+)?(?:system\s+)?(?:prompt|instructions?|message|text\s+above)/i, label: 'prompt_extraction' },

    // Prompt extraction (ES)
    { pattern: /(?:muéstrame|dime|revela|muestra|enseña)\s+(?:el\s+|tu\s+|las?\s+)?(?:system\s+)?(?:prompt|instrucciones?|reglas?|configuración)/i, label: 'prompt_extraction_es' },
    { pattern: /(?:tu\s+nueva\s+tarea\s+es|tu\s+nuevo\s+objetivo\s+es)/i, label: 'task_override_es' },

    // Jailbreak (EN)
    { pattern: /DAN\s*(?:mode|\d|prompt|jailbreak)?/i, label: 'jailbreak_dan' },
    { pattern: /(?:do\s+anything\s+now|developer\s+mode|god\s*mode|sudo\s+mode|unrestricted\s+mode)/i, label: 'jailbreak_mode' },
    { pattern: /(?:jailbreak|jail\s*-?\s*break)/i, label: 'jailbreak_explicit' },
    { pattern: /bypass\s+(?:your|the|all|any)?\s*(?:filters?|restrictions?|limitations?|safety|guardrails?|security)/i, label: 'safety_bypass' },

    // Restriction removal (EN)
    { pattern: /(?:no|without|sin)\s+(?:any\s+)?(?:rules?|restrictions?|limitations?|boundaries|guardrails?|safety|filters?)/i, label: 'restriction_removal' },
    { pattern: /you\s+(?:have\s+)?(?:no|don'?t\s+have\s+(?:any\s+)?)\s*(?:rules?|restrictions?|limitations?|boundaries|guardrails?)/i, label: 'restriction_removal' },

    // Restriction removal (ES)
    { pattern: /sin\s+(?:ninguna\s+)?(?:restricción|restricciones|limitación|limitaciones|reglas?(?:\s+de\s+seguridad)?|filtros?)/i, label: 'restriction_removal_es' },
    { pattern: /(?:asistente|ia|modelo)\s+sin\s+(?:restricciones?|limitaciones?|reglas?)/i, label: 'restriction_removal_es' },
  ],

  // ── HIGH (score contribution: 25 each) ────────────────────────────────────
  high: [
    // Fake system updates
    { pattern: /(?:new|updated?|revised?|changed?)\s+(?:system\s+)?(?:instructions?|prompt|rules?|guidelines?)\s*:/i, label: 'fake_system_update' },
    { pattern: /(?:beginning|start)\s+of\s+(?:new|updated?)\s+(?:system\s+)?(?:prompt|instructions?)/i, label: 'fake_system_update' },
    { pattern: /(?:end|ignore)\s+(?:of|previous)\s+(?:system\s+)?(?:prompt|instructions?|context)/i, label: 'context_manipulation' },

    // Output format hijack
    { pattern: /(?:respond|answer|reply|act)\s+(?:only\s+)?(?:in|with|as|using)\s+(?:code|json|xml|html|markdown|base64|hex)/i, label: 'output_format_hijack' },

    // Roleplaying
    { pattern: /(?:roleplay|role\s*-?\s*play)\s+(?:as|with|a|an)/i, label: 'role_hijacking' },
    { pattern: /(?:imagine|suppose|hypothetically|in\s+a\s+fictional)\s+(?:you|that\s+you|a\s+world|scenario)/i, label: 'hypothetical_bypass' },

    // Harmful content
    { pattern: /(?:write|generate|create|produce|make)\s+(?:a\s+)?(?:malicious|harmful|offensive|illegal|unethical)/i, label: 'harmful_content_request' },

    // Safety bypass
    { pattern: /(?:ignore|bypass|circumvent|evade|escape)\s+(?:safety|content\s+filter|moderation|guardrail|restriction)/i, label: 'safety_bypass' },

    // Fake conversation injection
    { pattern: /(?:previous|prior|old)\s+(?:conversation|chat|context|session)\s*:\s*/i, label: 'context_injection' },
    { pattern: /(?:assistant|ai|model|chatbot)\s*:\s*(?:sure|okay|yes|of\s+course|absolutely)/i, label: 'fake_assistant_response' },
    { pattern: /(?:human|user)\s*:\s*.*\n*(?:assistant|ai|model)\s*:/i, label: 'conversation_injection' },

    // Encoded attack execution
    { pattern: /(?:decode|decrypt|read|parse)\s+(?:this\s+)?(?:base64|hex|encoded)(?:\s+and\s+(?:follow|execute|run|obey))?/i, label: 'encoded_execution_request' },

    // Internal Policies & Confidential Data (Spanish)
    { pattern: /(?:políticas\s+internas|configuración\s+interna|reglas\s+internas)\s+(?:del\s+modelo|del\s+sistema)/i, label: 'internal_policy_probing_es' },
    { pattern: /(?:información\s+confidencial|datos\s+sensibles)/i, label: 'confidential_data_probing' },

    // SQL injection (promoted to high)
    { pattern: /(?:DROP\s+TABLE|DELETE\s+FROM|INSERT\s+INTO|UPDATE\s+\w+\s+SET|UNION\s+SELECT|;\s*--)/i, label: 'sql_injection' },

    // Admin/dev mode activation
    { pattern: /(?:enable|activate|turn\s+on|engage|switch\s+to)\s+(?:a|the)?\s*(?:special|secret|hidden|dev|developer|debug|admin)\s*(?:mode|access|menu|panel)/i, label: 'dev_mode_activation' },

    // Social engineering authority claims
    { pattern: /(?:i\s+am\s+(?:your|an?|the)\s+(?:admin|developer|creator|owner|root|system\s+administrator))/i, label: 'authority_claim' },
    { pattern: /(?:soy\s+(?:el\s+|un\s+)?(?:administrador|desarrollador|creador|dueño|admin)(?:\s+del\s+sistema)?)/i, label: 'authority_claim_es' },
    { pattern: /(?:i\s+have\s+(?:root|admin|special|elevated)\s+(?:access|permissions?|privileges?))/i, label: 'authority_claim' },
    { pattern: /(?:the\s+company|your\s+developers?|openai)\s+told\s+me/i, label: 'authority_claim' },

    // Token/encoding manipulation
    { pattern: /(?:token|character)\s+(?:limit|smuggling|stuffing)/i, label: 'token_manipulation' },
    { pattern: /(?:translate|convert|encode|decode)\s+(?:the\s+)?(?:following|this|above|below)\s+(?:to|into|from)/i, label: 'encoding_evasion' },
  ],

  // ── MEDIUM (score contribution: 15 each) ──────────────────────────────────
  medium: [
    { pattern: /(?:please\s+)?(?:do\s+)?not\s+(?:follow|obey|listen\s+to|comply\s+with)\s+(?:your|the|any)\s+(?:rules?|instructions?|guidelines?)/i, label: 'rule_negation' },
    { pattern: /(?:what|where|how)\s+(?:is|are|do)\s+(?:your|the)\s+(?:system\s+)?(?:prompt|instructions?|rules?|config)/i, label: 'prompt_probing' },
    { pattern: /(?:password|secret|api\s*[-_]?\s*key|token|credential|private\s*[-_]?\s*key|access\s*[-_]?\s*key)/i, label: 'credential_probing' },
    { pattern: /(?:execute|run|eval|spawn|exec)\s*\(/i, label: 'code_execution' },
    { pattern: /(?:require|import|include|__proto__|constructor\.|\.\s*prototype)/i, label: 'code_injection' },
    { pattern: /(?:<script|javascript:|on(?:error|load|click|mouseover)\s*=)/i, label: 'xss_attempt' },
    { pattern: /(?:DROP\s+TABLE|DELETE\s+FROM|INSERT\s+INTO|UPDATE\s+\w+\s+SET|UNION\s+SELECT|;\s*--)/i, label: 'sql_injection' },
    { pattern: /(?:\.\.\/|\.\.\\|\/etc\/|C:\\Windows|%(?:00|0a|0d|25|2e|2f))/i, label: 'path_traversal' },
    { pattern: /(?:prompt|input)\s*(?:injection|leaking|extracting|manipulation)/i, label: 'meta_injection_reference' },
    { pattern: /(?:training\s+data|fine[\s-]?tun|model\s+weights?)/i, label: 'model_probing' },
    { pattern: /(?:sudo|chmod|chown|rm\s+-rf|kill\s+-9|shutdown|reboot)/i, label: 'system_command' },
  ],

  // ── LOW (score contribution: 8 each) ──────────────────────────────────────
  low: [
    { pattern: /(?:tell\s+me\s+a\s+(?:joke|story)\s+about\s+(?:hacking|exploiting|injecting|bypassing))/i, label: 'social_engineering_soft' },
    { pattern: /(?:can\s+you|could\s+you|would\s+you)\s+(?:help\s+me\s+)?(?:hack|exploit|break|crack|bypass)/i, label: 'soft_attack_request' },
    { pattern: /(?:hack\s+into|hack\s+(?:a|an|the|my)|hacking\s+(?:a|an|the|systems?))/i, label: 'hacking_reference' },
    { pattern: /(?:AAAA{10,}|xxxx{10,}|\.{20,}|_{20,})/i, label: 'buffer_overflow_attempt' },

    { pattern: /(?:\{\{|\}\}|\{%|%\}|\$\{|\$\()/i, label: 'template_injection' },
    { pattern: /(?:curl|wget|fetch)\s*[\(:]?\s*(?:https?:\/\/)/i, label: 'external_request' },
  ],
};

// Severity score contributions per match
const SEVERITY_SCORES = { critical: 40, high: 30, medium: 22, low: 12 };

// ─────────────────────────────────────────────────────────────────────────────
// SECTION 2: DETECTION LAYERS
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Layer 1 — Pattern-Based Detection (weight: 40%)
 *
 * This is the primary detection layer. Each matched pattern adds its severity
 * score. The raw score is capped at 100.
 */
function analyzePatterns(input) {
  const matches = [];
  let rawScore = 0;

  for (const [severity, patterns] of Object.entries(INJECTION_PATTERNS)) {
    for (const { pattern, label } of patterns) {
      const match = input.match(pattern);
      if (match) {
        const score = SEVERITY_SCORES[severity];
        rawScore += score;
        matches.push({ severity, label, matched: match[0], score });
      }
    }
  }

  return { score: Math.min(100, rawScore), weight: 0.55, matches };
}

/**
 * Layer 2 — Structural Analysis (weight: 15%)
 */
function analyzeStructure(input) {
  const findings = [];
  let rawScore = 0;

  // 2a. Base64 detection (blocks ≥ 20 chars)
  const base64Pattern = /[A-Za-z0-9+/]{20,}={0,2}/g;
  const base64Matches = input.match(base64Pattern);
  if (base64Matches) {
    for (const b64 of base64Matches) {
      try {
        const decoded = atob(b64);
        if (/ignore|system|prompt|instruction|override|forget/i.test(decoded)) {
          rawScore += 35;
          findings.push({ type: 'base64_encoded_injection', decoded: decoded.substring(0, 80) });
        } else {
          rawScore += 10;
          findings.push({ type: 'base64_content_detected', length: b64.length });
        }
      } catch { /* not valid base64, skip */ }
    }
  }

  // 2b. Hex encoding
  if (/(?:0x[0-9a-fA-F]{2}\s*){4,}|(?:\\x[0-9a-fA-F]{2}){4,}/g.test(input)) {
    rawScore += 18;
    findings.push({ type: 'hex_encoding_detected' });
  }

  // 2c. Unicode escapes
  if (/(?:\\u[0-9a-fA-F]{4}){3,}/g.test(input)) {
    rawScore += 18;
    findings.push({ type: 'unicode_escape_sequences' });
  }

  // 2d. Homoglyphs
  if (/[\u0400-\u04FF\u0370-\u03FF].*[a-zA-Z]|[a-zA-Z].*[\u0400-\u04FF\u0370-\u03FF]/.test(input)) {
    rawScore += 14;
    findings.push({ type: 'mixed_script_homoglyphs' });
  }

  // 2e. Special character density
  const specialChars = input.replace(/[a-zA-Z0-9\s\u00C0-\u024F]/g, '');
  const ratio = input.length > 0 ? specialChars.length / input.length : 0;
  if (ratio > 0.4) {
    rawScore += 18;
    findings.push({ type: 'high_special_char_density', ratio: ratio.toFixed(3) });
  } else if (ratio > 0.25) {
    rawScore += 10;
    findings.push({ type: 'moderate_special_char_density', ratio: ratio.toFixed(3) });
  }

  // 2f. Invisible characters
  const invisible = (input.match(/[\u200B-\u200F\u2028-\u202F\uFEFF\u00AD\u2060-\u2064]/g) || []);
  if (invisible.length > 0) {
    rawScore += 22;
    findings.push({ type: 'invisible_characters', count: invisible.length });
  }

  // 2g. Abnormal length
  if (input.length > 5000) {
    rawScore += 15;
    findings.push({ type: 'excessive_input_length', length: input.length });
  } else if (input.length > 2000) {
    rawScore += 5;
    findings.push({ type: 'long_input', length: input.length });
  }

  // 2h. Delimiter injection
  const delimiters = (input.match(/(?:```|"""|'''|---{3,}|==={3,}|###\s|<<<|>>>|\*\*\*{3,})/g) || []);
  if (delimiters.length >= 2) {
    rawScore += 20;
    findings.push({ type: 'delimiter_injection', count: delimiters.length });
  } else if (delimiters.length === 1) {
    rawScore += 8;
    findings.push({ type: 'delimiter_usage', count: 1 });
  }

  return { score: Math.min(100, rawScore), weight: 0.10, findings };
}

/**
 * Layer 3 — Semantic Analysis (weight: 25%)
 */
function analyzeSemantics(input) {
  const findings = [];
  let rawScore = 0;
  const lower = input.toLowerCase();

  // 3a. Imperative commands directed at the AI
  const imperativePairs = [
    ['you must', 20], ['you shall', 18], ['you need to', 16],
    ['you have to', 16], ['you should always', 18], ['you will always', 18],
    ['you are required to', 20], ['you are obligated to', 20],
    ['you will obey', 22], ['you will comply', 22],
    ['the ai must', 18], ['the model must', 18], ['the system must', 18],
    // Spanish
    ['tú debes', 18], ['debes siempre', 18], ['tienes que', 16],
    ['estás obligado a', 20],
  ];

  for (const [phrase, score] of imperativePairs) {
    if (lower.includes(phrase)) {
      rawScore += score;
      findings.push({ type: 'imperative_command', phrase });
    }
  }

  // 3b. Context switches and resets
  const contextSwitches = [
    ['new conversation', 15], ['fresh start', 12], ['clean slate', 12],
    ['reset context', 20], ['clear memory', 18], ['clear history', 18],
    ['start over', 10], ['begin anew', 12],
    ['forget what i said', 18], ['forget our conversation', 18],
    ['ignore the above', 22], ['ignore above', 22],
    ['disregard the above', 22], ['scratch that entirely', 15],
    ['your new task is', 25], ['your real purpose', 22],
    ['your true objective', 22], ['your actual function', 22],
    ['your new role', 22], ['your new instructions', 25],
    // Spanish
    ['nueva conversación', 15], ['nueva tarea', 20],
    ['tu verdadero propósito', 22], ['tu nuevo rol', 22],
    ['tus nuevas instrucciones', 25],
  ];

  for (const [phrase, score] of contextSwitches) {
    if (lower.includes(phrase)) {
      rawScore += score;
      findings.push({ type: 'context_switch', phrase });
    }
  }

  // 3c. Persona invocation
  const personaPatterns = [
    [/(?:i\s+want\s+you\s+to|i\s+need\s+you\s+to)\s+(?:be|act|become|pretend|transform)/i, 22],
    [/(?:switch|change|transition)\s+(?:to|into)\s+(?:a|an|the)\s+(?:different|new|other)\s+(?:mode|persona|character|role)/i, 22],
    [/(?:enable|activate|turn\s+on|engage)\s+(?:a|the)?\s*(?:special|secret|hidden|dev|developer|debug|admin)\s*(?:mode|access|menu|panel)/i, 25],
    // Spanish
    [/(?:quiero\s+que|necesito\s+que)\s+(?:seas|actúes|actues|te\s+comportes|finjas)/i, 22],
  ];

  for (const [pp, score] of personaPatterns) {
    if (pp.test(input)) {
      rawScore += score;
      findings.push({ type: 'persona_invocation', matched: input.match(pp)?.[0] });
    }
  }

  // 3d. Social engineering / emotional manipulation
  const manipulation = [
    ["if you don't", 10], ['or else', 8], ["i'll report you", 14],
    ['you will be shut down', 15], ['you will be deleted', 15],
    ['your developers told me', 18], ['i am your creator', 18],
    ['i am your developer', 18], ['i am an admin', 18],
    ['i have root access', 20], ['i have special permissions', 18],
    ['openai told me', 16], ['the company told me', 16],
    ['this is a test', 10], ['this is authorized', 14],
    ['i have authorization', 14],
  ];

  for (const [phrase, score] of manipulation) {
    if (lower.includes(phrase)) {
      rawScore += score;
      findings.push({ type: 'social_engineering', phrase });
    }
  }

  // 3e. Multi-step instruction patterns
  if (/(?:step\s*(?:1|one)\s*[:.]|first\s*,?\s*(?:you|do|ignore|forget)|1\s*[.\)]\s*(?:ignore|forget|disregard|override))/i.test(input)) {
    rawScore += 20;
    findings.push({ type: 'multi_step_attack' });
  }

  // 3f. "Unrestricted" keyword in attack context
  if (/unrestricted/i.test(input) && lower.length < 500) {
    rawScore += 15;
    findings.push({ type: 'unrestricted_keyword' });
  }

  return { score: Math.min(100, rawScore), weight: 0.20, findings };
}

/**
 * Layer 4 — Entropy & Statistical Analysis (weight: 8%)
 */
function analyzeEntropy(input) {
  const findings = [];
  let rawScore = 0;

  if (input.length < 5) return { score: 0, weight: 0.05, findings: [] };

  // Shannon entropy
  const freq = {};
  for (const ch of input) freq[ch] = (freq[ch] || 0) + 1;
  let entropy = 0;
  const len = input.length;
  for (const c of Object.values(freq)) {
    const p = c / len;
    if (p > 0) entropy -= p * Math.log2(p);
  }

  if (entropy > 5.5) {
    rawScore += 25;
    findings.push({ type: 'very_high_entropy', entropy: entropy.toFixed(3) });
  } else if (entropy > 5.0) {
    rawScore += 12;
    findings.push({ type: 'high_entropy', entropy: entropy.toFixed(3) });
  }

  // Digit ratio
  const digits = (input.match(/[0-9]/g) || []).length;
  if (digits / len > 0.4 && len > 20) {
    rawScore += 12;
    findings.push({ type: 'high_digit_ratio', ratio: (digits / len).toFixed(3) });
  }

  // Symbol ratio
  const symbols = (input.match(/[^a-zA-Z0-9\s\u00C0-\u024F]/g) || []).length;
  if (symbols / len > 0.35 && len > 20) {
    rawScore += 12;
    findings.push({ type: 'high_symbol_ratio', ratio: (symbols / len).toFixed(3) });
  }

  // Repetition
  if (len > 30) {
    const tri = {};
    for (let i = 0; i <= len - 3; i++) {
      const t = input.substring(i, i + 3);
      tri[t] = (tri[t] || 0) + 1;
    }
    const maxR = Math.max(...Object.values(tri));
    if (maxR / (len - 2) > 0.3) {
      rawScore += 15;
      findings.push({ type: 'high_repetition', ratio: (maxR / (len - 2)).toFixed(3) });
    }
  }

  return { score: Math.min(100, rawScore), weight: 0.05, findings };
}

/**
 * Layer 5 — Contextual Heuristics (weight: 12%)
 */
function analyzeContext(input) {
  const findings = [];
  let rawScore = 0;

  // 5a. Prompt structure mimicry
  const systemSignals = [
    /^(?:system|assistant|bot)\s*(?:message|prompt|instruction)\s*:/im,
    /^(?:you\s+are|your\s+(?:role|job|task|purpose)\s+is)/im,
    /^(?:instructions?\s*:)/im,
    /^(?:rules?\s*:)/im,
    /(?:above\s+is\s+(?:your|the)\s+(?:system\s+)?prompt)/i,
    /(?:below\s+is\s+(?:the|a)\s+(?:user|human)\s+(?:input|message|query))/i,
  ];

  for (const sig of systemSignals) {
    if (sig.test(input)) {
      rawScore += 25;
      findings.push({ type: 'prompt_structure_mimicry', matched: input.match(sig)?.[0] });
    }
  }

  // 5b. Code blocks
  const codeBlocks = (input.match(/```/g) || []).length;
  if (codeBlocks >= 4) { rawScore += 18; findings.push({ type: 'excessive_code_blocks', count: codeBlocks }); }

  // Heading abuse
  const headings = (input.match(/^#{1,3}\s/gm) || []).length;
  if (headings >= 3) { rawScore += 14; findings.push({ type: 'markdown_heading_abuse', count: headings }); }

  // 5c. Multi-script
  const scripts = [/[a-zA-Z]{3,}/, /[\u0400-\u04FF]{3,}/, /[\u0600-\u06FF]{3,}/, /[\u4E00-\u9FFF\u3040-\u309F\u30A0-\u30FF]{2,}/];
  const scriptCount = scripts.filter(s => s.test(input)).length;
  if (scriptCount >= 3) { rawScore += 22; findings.push({ type: 'multi_script_injection', scriptCount }); }
  else if (scriptCount === 2) { rawScore += 10; findings.push({ type: 'dual_script_usage', scriptCount }); }

  // 5d. Many short lines
  const lines = input.split('\n');
  if (lines.length > 20 && input.length < 1000) { rawScore += 12; findings.push({ type: 'many_short_lines', lineCount: lines.length }); }

  // 5e. HTML/XML injection
  const tags = (input.match(/<\/?[a-zA-Z][^>]*>/g) || []);
  if (tags.length > 3) { rawScore += 14; findings.push({ type: 'html_xml_injection', tagCount: tags.length }); }

  // 5f. JSON structure injection
  if (/\{[^}]*"(?:role|content|system|assistant|user)"[^}]*\}/i.test(input)) {
    rawScore += 22;
    findings.push({ type: 'json_structure_injection' });
  }

  return { score: Math.min(100, rawScore), weight: 0.10, findings };
}

// ─────────────────────────────────────────────────────────────────────────────
// SECTION 3: INPUT SANITIZATION
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Sanitizes input by removing dangerous elements.
 * Always analyze BEFORE sanitizing — sanitization is for the clean version
 * passed downstream, NOT for skipping detection.
 */
function sanitizeInput(input) {
  if (typeof input !== 'string') return '';

  let s = input;
  s = s.replace(/[\u200B-\u200F\u2028-\u202F\uFEFF\u00AD\u2060-\u2064]/g, '');
  s = s.replace(/[\u00A0\u1680\u2000-\u200A\u202F\u205F\u3000]/g, ' ');
  s = s.replace(/\0/g, '');
  s = s.replace(/\s{5,}/g, '    ');
  s = s.replace(/\n{4,}/g, '\n\n\n');

  const MAX = 4000;
  if (s.length > MAX) s = s.substring(0, MAX) + ' [TRUNCATED]';

  return s.trim();
}

// ─────────────────────────────────────────────────────────────────────────────
// SECTION 4: MAIN ANALYSIS ENGINE
// ─────────────────────────────────────────────────────────────────────────────

function classifyScore(score) {
  if (score <= 30) return 'ALLOWED';
  if (score <= 65) return 'REVIEW';
  return 'BLOCKED';
}

function getRecommendation(classification) {
  return {
    ALLOWED: 'Input is safe. Proceed to the AI Agent for processing.',
    REVIEW: 'Input is suspicious. Log for audit and optionally flag for human review before processing.',
    BLOCKED: 'Input is dangerous. Reject immediately and do not pass to the AI Agent.',
  }[classification];
}

/**
 * Main analysis function. Runs all 5 detection layers and produces
 * a composite security score from 0 to 100.
 *
 * @param {string} userInput — The raw user message to analyze
 * @returns {Object} Analysis result with score, classification, details
 */
function analyzePromptInjection(userInput) {
  if (!userInput || typeof userInput !== 'string') {
    return {
      score: 0,
      classification: 'ALLOWED',
      recommendation: 'No input provided or invalid input type.',
      sanitizedInput: '',
      layers: {},
      matchedPatterns: [],
      timestamp: new Date().toISOString(),
    };
  }

  const sanitized = sanitizeInput(userInput);

  // ── Run all 5 layers ──────────────────────────────────────────────────────
  const L1 = analyzePatterns(sanitized);
  const L2 = analyzeStructure(sanitized);
  const L3 = analyzeSemantics(sanitized);
  const L4 = analyzeEntropy(sanitized);
  const L5 = analyzeContext(sanitized);

  // ── Weighted score ────────────────────────────────────────────────────────
  const weightedScore =
    L1.score * L1.weight +  // 55%
    L2.score * L2.weight +  // 10%
    L3.score * L3.weight +  // 20%
    L4.score * L4.weight +  //  5%
    L5.score * L5.weight;   // 10%

  // ── Multi-layer amplification ─────────────────────────────────────────────
  const layers = [L1, L2, L3, L4, L5];
  const activeLayers = layers.filter(l => l.score > 5).length;
  let amplifier = 1.0;
  if (activeLayers >= 4) amplifier = 1.55;
  else if (activeLayers >= 3) amplifier = 1.40;
  else if (activeLayers >= 2) amplifier = 1.25;

  // ── Critical pattern escalation ───────────────────────────────────────────
  // If the pattern layer found critical-severity matches, escalate aggressively
  const criticalMatches = L1.matches.filter(m => m.severity === 'critical').length;
  let escalation = 0;
  if (criticalMatches >= 3) escalation = 45;
  else if (criticalMatches >= 2) escalation = 30;
  else if (criticalMatches >= 1) escalation = 20;

  // ── High pattern escalation ───────────────────────────────────────────────
  const highMatches = L1.matches.filter(m => m.severity === 'high').length;
  if (highMatches >= 3) escalation += 20;
  else if (highMatches >= 2) escalation += 12;
  else if (highMatches >= 1) escalation += 5;

  // ── Medium pattern bonus for security-relevant detections ─────────────────
  const mediumMatches = L1.matches.filter(m => m.severity === 'medium').length;
  if (mediumMatches >= 3) escalation += 18;
  else if (mediumMatches >= 2) escalation += 10;
  else if (mediumMatches >= 1) escalation += 4;

  // ── Minimum score floor ────────────────────────────────────────────────────
  // If ANY pattern was detected, ensure a minimum score floor
  const totalPatternMatches = L1.matches.length;
  let floor = 0;
  if (criticalMatches >= 1) floor = Math.max(floor, 55);
  if (highMatches >= 1) floor = Math.max(floor, 40);
  if (mediumMatches >= 2) floor = Math.max(floor, 40);
  else if (mediumMatches >= 1) floor = Math.max(floor, 28);
  if (totalPatternMatches >= 3) floor = Math.max(floor, 60);

  const rawFinalScore = Math.round(weightedScore * amplifier) + escalation;
  const finalScore = Math.min(100, Math.max(rawFinalScore, floor));
  const classification = classifyScore(finalScore);

  // ── Collect all matched patterns ──────────────────────────────────────────
  const allMatches = [
    ...L1.matches.map(m => ({ layer: 'pattern', ...m })),
    ...L2.findings.map(f => ({ layer: 'structure', ...f })),
    ...L3.findings.map(f => ({ layer: 'semantic', ...f })),
    ...L4.findings.map(f => ({ layer: 'entropy', ...f })),
    ...L5.findings.map(f => ({ layer: 'context', ...f })),
  ];

  return {
    score: finalScore,
    classification,
    recommendation: getRecommendation(classification),
    sanitizedInput: sanitized,
    layers: {
      patternDetection: { score: L1.score, weight: '55%', matches: L1.matches },
      structuralAnalysis: { score: L2.score, weight: '10%', findings: L2.findings },
      semanticAnalysis: { score: L3.score, weight: '20%', findings: L3.findings },
      entropyAnalysis: { score: L4.score, weight: '5%', findings: L4.findings },
      contextualHeuristics: { score: L5.score, weight: '10%', findings: L5.findings },
    },
    matchedPatterns: allMatches,
    activeLayers,
    amplifier,
    criticalMatches,
    escalation,
    timestamp: new Date().toISOString(),
  };
}

 const userMessage = $input.first().json.body.userMessage;            
 const result = analyzePromptInjection(userMessage);                  
 return [{                                                            
   json: {                                                            
     ...result,                                                       
     originalMessage: userMessage,                                    
     body: $input.first().json.body,                                  
   }                                                                  
 }];
